import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function ParkingList() {
  const [lots, setLots] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    console.log("Fetching parking lots...");
    axios.get("/parking")
      .then(res => {
        console.log("Got lots:", res.data);
        setLots(res.data);
      })
      .catch(err => {
        console.error("Error fetching lots:", err);
        alert("Failed to fetch parking lots. Check console/backend.");
      });
  }, []);

  return (
    <div className="container">
      <h2>Available Parking Lots ({lots.length} Found)</h2>
      <div className="grid">
        {lots.length === 0 && <p style={{ gridColumn: "1/-1", textAlign: "center" }}>No parking lots found (or loading...).</p>}
        {lots.map(lot => (
          <div className="card" key={lot._id}>
            <div>
              <h3>{lot.name}</h3>
              <p>📍 {lot.location}</p>
            </div>
            <button className="btn-primary" onClick={() => navigate(`/slots/${lot._id}`)}>
              View Availability →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
